/**
 * n8n Code node
 * AI Receptionist V2
 * - AI understanding
 * - question answering
 * - lead intake
 * - 30 minute timeout reset
 */

const webhookJson = $('Webhook').first().json || {};
const payload = webhookJson.body || {};

const from = String(payload.From ?? webhookJson.From ?? "").trim();
const to = String(payload.To ?? webhookJson.To ?? "").trim();
const body = String(payload.Body ?? webhookJson.Body ?? "").trim();
const lowerBody = body.toLowerCase();

if (!from || !to) {
  return [
    {
      json: {
        from,
        to,
        inboundBody: body,
        reply: "Missing phone information. Please try again.",
        done: false,
        summary: "",
        service: "",
        location: "",
        timeline: "",
        bestTime: "",
      },
    },
  ];
}

// ----- AI output handling -----
const aiNodeJson = $('AI Agent').first().json || {};

let aiRaw =
  aiNodeJson.output ??
  aiNodeJson.text ??
  aiNodeJson.response ??
  aiNodeJson.data ??
  null;

let aiData = {};

if (typeof aiRaw === "string") {
  try {
    aiData = JSON.parse(aiRaw);
  } catch {
    aiData = {};
  }
} else if (aiRaw && typeof aiRaw === "object") {
  aiData = aiRaw;
}

const aiService = aiData.service || null;
const aiLocation = aiData.location || null;
const aiTimeline = aiData.timeline || null;
const aiBestTime = aiData.bestTime || null;
const aiIsQuestion = aiData.isQuestion || false;
const aiQuestionType = aiData.questionType || null;
const aiAnswer = aiData.answer || null;

// ----- Storage -----
const store = $getWorkflowStaticData("global");
store.conversations ||= {};
store.optOut ||= {};

const key = `${to}:${from}`;

const serviceMap = {
  "1": "mowing",
  "2": "cleanup",
  "3": "mulch/landscaping",
};

const timelineMap = {
  "1": "ASAP",
  "2": "this week",
  "3": "just getting a quote",
};

const bestTimeMap = {
  "1": "morning",
  "2": "afternoon",
  "3": "evening",
};

const TIMEOUT_MINUTES = 30;
const TIMEOUT_MS = TIMEOUT_MINUTES * 60 * 1000;

function resetConversation() {
  store.conversations[key] = {
    step: 1,
    answers: {},
    lastUpdatedAt: Date.now(),
  };
}

// ----- STOP / START -----
if (["stop", "unsubscribe", "cancel", "end", "quit"].includes(lowerBody)) {
  store.optOut[key] = true;
  delete store.conversations[key];

  return [
    {
      json: {
        from,
        to,
        inboundBody: body,
        reply: "You’re opted out. Reply START to re-subscribe.",
        done: false,
        summary: "",
        service: "",
        location: "",
        timeline: "",
        bestTime: "",
      },
    },
  ];
}

if (lowerBody === "start") {
  delete store.optOut[key];
  resetConversation();

  return [
    {
      json: {
        from,
        to,
        inboundBody: body,
        reply:
          "Hi! Thanks for contacting us.\n\nWhat service do you need?\nReply:\n1) mowing\n2) cleanup\n3) mulch/landscaping",
        done: false,
        summary: "",
        service: "",
        location: "",
        timeline: "",
        bestTime: "",
      },
    },
  ];
}

if (store.optOut[key]) {
  return [
    {
      json: {
        from,
        to,
        inboundBody: body,
        reply: "You’re opted out. Reply START to re-subscribe.",
        done: false,
        summary: "",
        service: "",
        location: "",
        timeline: "",
        bestTime: "",
      },
    },
  ];
}

if (!store.conversations[key]) {
  resetConversation();
}

const convo = store.conversations[key];
convo.answers ||= {};

// ----- Timeout reset -----
const now = Date.now();
const lastUpdatedAt = convo.lastUpdatedAt || now;
const timedOut = now - lastUpdatedAt > TIMEOUT_MS;

if (timedOut) {
  resetConversation();
}

const currentConvo = store.conversations[key];
currentConvo.answers ||= {};

let reply = "";
let done = false;

// ----- AI-first entry point -----
if (currentConvo.step === 1) {
  if (aiService) currentConvo.answers.service = aiService;
  if (aiLocation) currentConvo.answers.location = aiLocation;
  if (aiTimeline) currentConvo.answers.timeline = aiTimeline;
  if (aiBestTime) currentConvo.answers.bestTime = aiBestTime;

  if (aiIsQuestion && aiAnswer) {
    if (
      currentConvo.answers.service ||
      currentConvo.answers.location ||
      currentConvo.answers.timeline ||
      currentConvo.answers.bestTime
    ) {
      if (!currentConvo.answers.service) {
        reply = `${aiAnswer}\n\nWhat service do you need?\nReply:\n1) mowing\n2) cleanup\n3) mulch/landscaping`;
        currentConvo.step = 2;
      } else if (!currentConvo.answers.location) {
        reply = `${aiAnswer}\n\nGot it. What city or ZIP code is the property in?`;
        currentConvo.step = 3;
      } else if (!currentConvo.answers.timeline) {
        reply = `${aiAnswer}\n\nWhen would you like the work done?\nReply:\n1) ASAP\n2) this week\n3) just getting a quote`;
        currentConvo.step = 4;
      } else if (!currentConvo.answers.bestTime) {
        reply = `${aiAnswer}\n\nWhat is the best time to contact you?\nReply:\n1) morning\n2) afternoon\n3) evening`;
        currentConvo.step = 5;
      } else {
        reply = `${aiAnswer}\n\nThanks! Your request has been sent to our team. Someone will reach out shortly.`;
        done = true;
      }
    } else {
      reply = aiAnswer;
      currentConvo.step = 1;
    }
  } else if (!currentConvo.answers.service) {
    reply =
      "Hi! Thanks for contacting us.\n\nWhat service do you need?\nReply:\n1) mowing\n2) cleanup\n3) mulch/landscaping";
    currentConvo.step = 2;
  } else if (!currentConvo.answers.location) {
    reply = "Got it. What city or ZIP code is the property in?";
    currentConvo.step = 3;
  } else if (!currentConvo.answers.timeline) {
    reply =
      "When would you like the work done?\nReply:\n1) ASAP\n2) this week\n3) just getting a quote";
    currentConvo.step = 4;
  } else if (!currentConvo.answers.bestTime) {
    reply =
      "What is the best time to contact you?\nReply:\n1) morning\n2) afternoon\n3) evening";
    currentConvo.step = 5;
  } else {
    reply =
      "Thanks! Your request has been sent to our team. Someone will reach out shortly.";
    done = true;
  }
} else {
  switch (currentConvo.step) {
    case 2: {
      currentConvo.answers.service = serviceMap[body] || body;
      reply = "Got it. What city or ZIP code is the property in?";
      currentConvo.step = 3;
      break;
    }

    case 3: {
      currentConvo.answers.location = body;
      reply =
        "When would you like the work done?\nReply:\n1) ASAP\n2) this week\n3) just getting a quote";
      currentConvo.step = 4;
      break;
    }

    case 4: {
      currentConvo.answers.timeline = timelineMap[body] || body;
      reply =
        "What is the best time to contact you?\nReply:\n1) morning\n2) afternoon\n3) evening";
      currentConvo.step = 5;
      break;
    }

    case 5: {
      currentConvo.answers.bestTime = bestTimeMap[body] || body;
      reply =
        "Thanks! Your request has been sent to our team. Someone will reach out shortly.";
      done = true;
      break;
    }

    default: {
      resetConversation();
      reply =
        "Hi! Thanks for contacting us.\n\nWhat service do you need?\nReply:\n1) mowing\n2) cleanup\n3) mulch/landscaping";
      store.conversations[key].step = 2;
      break;
    }
  }
}

currentConvo.lastUpdatedAt = now;

const finalAnswers = { ...currentConvo.answers };

const summary =
  `New lead captured\n` +
  `From: ${from}\n` +
  `Service: ${finalAnswers.service || "(missing)"}\n` +
  `Location: ${finalAnswers.location || "(missing)"}\n` +
  `Timeline: ${finalAnswers.timeline || "(missing)"}\n` +
  `Best time: ${finalAnswers.bestTime || "(missing)"}`;

if (done) {
  resetConversation();
}

return [
  {
    json: {
      from,
      to,
      inboundBody: body,
      reply,
      done,
      summary,
      service: String(finalAnswers.service || ""),
      location: String(finalAnswers.location || ""),
      timeline: String(finalAnswers.timeline || ""),
      bestTime: String(finalAnswers.bestTime || ""),
      aiRaw,
      aiData,
      aiIsQuestion,
      aiQuestionType,
      aiAnswer,
      timedOut,
    },
  },
];
